#!/usr/bin/env node
// Auto-stamp the root README and docs/* with live counts pulled from
// version.json (which is itself generated by sync-version.mjs from
// package.json + spec/ frontmatter). Run after sync-version.mjs to keep
// the README's badges, file count, last-updated date, and version line
// in lockstep with the spec tree. Wired into the `sync` npm script.
//
// Stamp markers used in README/docs:
//   <!-- STAMP:VERSION -->...<!-- /STAMP:VERSION -->
//   <!-- STAMP:UPDATED -->...<!-- /STAMP:UPDATED -->
//   <!-- STAMP:FILES -->...<!-- /STAMP:FILES -->
//   <!-- STAMP:FOLDERS -->...<!-- /STAMP:FOLDERS -->
//   <!-- STAMP:LINES -->...<!-- /STAMP:LINES -->
//   <!-- STAMP:BADGES -->...<!-- /STAMP:BADGES -->

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const VERSION_PATH = resolve(ROOT, "version.json");

function loadStats() {
  const raw = JSON.parse(readFileSync(VERSION_PATH, "utf8"));
  return {
    version: raw.version,
    updated: raw.updated,
    files: raw.stats?.totalFiles ?? 0,
    folders: raw.stats?.totalFolders ?? 0,
    lines: raw.stats?.totalLines ?? 0,
  };
}

function buildBadges(s) {
  const repo = "alimtvnetwork/coding-guidelines-v15";
  // shields.io uses `--` to render a literal dash in the value segment.
  const escDash = (v) => String(v).replace(/-/g, "--");
  const enc = (v) => encodeURIComponent(escDash(v));
  return [
    `[![Version](https://img.shields.io/badge/version-${enc(s.version)}-3B82F6?style=flat-square)](https://github.com/${repo}/releases)`,
    `[![Spec Files](https://img.shields.io/badge/spec%20files-${enc(s.files)}-10B981?style=flat-square)](spec/)`,
    `[![Folders](https://img.shields.io/badge/folders-${enc(s.folders)}-8B5CF6?style=flat-square)](spec/)`,
    `[![Lines](https://img.shields.io/badge/lines-${enc(s.lines.toLocaleString())}-F59E0B?style=flat-square)](version.json)`,
    `[![License](https://img.shields.io/badge/license-MIT-22C55E?style=flat-square)](LICENSE)`,
    `[![AI Ready](https://img.shields.io/badge/AI%20ready-yes-FF6E3C?style=flat-square)](llm.md)`,
    `[![Updated](https://img.shields.io/badge/updated-${enc(s.updated)}-0EA5E9?style=flat-square)](version.json)`,
  ].join(" ");
}

function replaceMarker(body, key, value) {
  const re = new RegExp(`<!-- STAMP:${key} -->[\\s\\S]*?<!-- /STAMP:${key} -->`, "g");
  const replacement = `<!-- STAMP:${key} -->${value}<!-- /STAMP:${key} -->`;
  return body.replace(re, replacement);
}

function stampFile(relPath, stats) {
  const path = resolve(ROOT, relPath);
  if (!existsSync(path)) return false;
  const before = readFileSync(path, "utf8");
  let after = before;
  after = replaceMarker(after, "VERSION", stats.version);
  after = replaceMarker(after, "UPDATED", stats.updated);
  after = replaceMarker(after, "FILES", String(stats.files));
  after = replaceMarker(after, "FOLDERS", String(stats.folders));
  after = replaceMarker(after, "LINES", stats.lines.toLocaleString());
  after = replaceMarker(after, "BADGES", buildBadges(stats));
  if (after === before) return false;
  writeFileSync(path, after);
  return true;
}

function main() {
  const stats = loadStats();
  const targets = ["readme.md", "docs/architecture.md", "docs/principles.md", "docs/author.md"];
  const changed = targets.filter((t) => stampFile(t, stats));
  console.log(`[sync-readme-stats] v${stats.version} files=${stats.files} folders=${stats.folders} lines=${stats.lines.toLocaleString()}`);
  console.log(`[sync-readme-stats] stamped: ${changed.length ? changed.join(", ") : "(none — markers absent or already current)"}`);
}

main();